#include <stdio.h>
int sum_array(const int *arr, int n) {
    int sum = 0;
    for (int i = 0; i < n; i++) {
        sum += *(arr + i);
    }
    return sum;
}
int main(void) {
    int nums[] = {10, 20, 30, 40, 50};
    int total = sum_array(nums, 5);
    printf("Somme : %d\n", total);
    printf("Element 2 : %d\n", *(nums + 2));
    return 0;
}

