#include <stdio.h>

// ★ Stage 0 — Exemple complet
// ★ p+i est équivalent à &arr[i]
// ★ *(p+i) est équivalent à arr[i]
int sum_array(const int *arr, int n) {
    int sum = 0;
    for (int i = 0; i < n; i++) {
        sum += *(arr + i); // ★ arithmétique de pointeurs
    }
    return sum;
}
int main(void) {
    int nums[] = {10, 20, 30, 40, 50};
    int total = sum_array(nums, 5);
    printf("Somme : %d\n", total);
    printf("Element 2 : %d\n", *(nums + 2)); // ★ accès sans crochets
    return 0;
}

